package org.traccar.protocol;

import org.junit.jupiter.api.Test;
import org.traccar.ProtocolTest;

public class Jt1078FrameDecoderTest extends ProtocolTest {

    @Test
    public void testDecode() throws Exception {

        var decoder = inject(new Jt1078FrameDecoder());

        verifyFrame(
                binary(""),
                decoder.decode(null, null, binary("")));

        verifyNull(decoder.decode(null, null,
                binary("3031636480610001")));

    }

}
